    if (content.includes(p)) return true;
  }
  return false;
}

function isSelf(msg) {
  return msg?.message?.sender?.uid === SELF_UID;
}

function isEmojiOnly(content) {
  if (!content) return false;
  const cleaned = content.replace(/\/:[\w]+\.?/g, '').trim();
  // Also handle basic emojis
  const emojiOnly = content.match(/^(\/:[\w]+\.?\s*)+$/);
  if (emojiOnly) return true;
  // Single word replies
  const singleWord = ['OK', 'ok', 'Okay', 'okay', 'Yes', 'yes', 'No', 'no', '好的', '👌'];
  if (singleWord.includes(cleaned)) return true;
  return false;
}

// Signal detection
function detectSignals(content) {
  const signals = [];
  const lower = (content || '').toLowerCase();

  // Price/quote signals
  if (lower.match(/price|报价|quote|سعر|prix|precio|preço|стоимость|السعر/)) signals.push('PRICE');
  if (lower.match(/\$\d+|\d+\s*usd|\d+\s*dollar/)) signals.push('SPECIFIC_PRICE');

  // Order signals
  if (lower.match(/order|make order|place order|下单|заказ|pedido|commande/)) signals.push('ORDER');
  if (lower.match(/pi\b|proforma invoice|proforma|发票/)) signals.push('PI');

  // Address/delivery
  if (lower.match(/address|delivery|ship|freight|shipping|物流|地址|livraison|envío|الشحن|عنوان/)) signals.push('SHIPPING');
  if (lower.match(/dap|ddp|fob|exw|cif|door to door/)) signals.push('INCOTERMS');

  // Payment
  if (lower.match(/payment|paid|deposit|预付|定金|проплата|depósito|acompte/)) signals.push('PAYMENT');
  if (lower.match(/40%|30%|50%|tt\b|bank transfer|alibaba trade/)) signals.push('PAYMENT_TERMS');

  // Product selection
  if (lower.match(/style|pattern|design|color|size|material|cotton|款|色|码|面料|talla|taille/)) signals.push('PRODUCT');

  // Sample
  if (lower.match(/sample|样品|muestra|echantillon|عينة/)) signals.push('SAMPLE');

  // Quantity
  if (lower.match(/quantity|qty|数量|quantité|cantidad|количество|كمية/)) signals.push('QTY');
  if (lower.match(/\d+\s*(pcs|pieces|件|pièces)/)) signals.push('SPECIFIC_QTY');

  // Decision maker
  if (lower.match(/partner|brother|husband|wife|boss|manager|商量|discuss|consult|partenaire/)) signals.push('DECISION_CHAIN');

  // Urgency
  if (lower.match(/urgent|asap|尽快|urgente/)) signals.push('URGENT');

  return signals;
}

function toDaysAgo(ts) {
  return Math.round((Date.now() - ts) / 86400000);
}

function analyzeConversation(cid, name, country, metaInfo) {
  const fileName = cid.replace(/#/g, '_').replace(/@/g, '_') + '.json';
  const filePath = path.join(chatDir, fileName);

  if (!fs.existsSync(filePath)) {
    return { name, country, error: 'FILE_NOT_FOUND', msgCount: 0 };
  }

  const data = JSON.parse(fs.readFileSync(filePath, 'utf8'));
  const messages = data.messages || [];

  // Filter out system messages and auto-replies
  const realMessages = messages.filter(m => {
    const ext = m?.message?.extension?.basicMessageInfo;
    if (ext) {
      try {
        const info = JSON.parse(ext);
        if (info.systemMessage === true || info.autoReply === true) return false;
      } catch(e) {}
    }
    const content = m?.message?.content?.text?.content || '';
    return !isSystemMsg(content);
  });

  const selfMsgs = realMessages.filter(m => isSelf(m));
  const clientMsgs = realMessages.filter(m => !isSelf(m));

  // Timeline
  const allTimestamps = realMessages.map(m => m?.message?.createAt || 0).filter(Boolean);
  const firstContact = allTimestamps.length > 0 ? toDaysAgo(Math.min(...allTimestamps)) : null;
  const lastContact = allTimestamps.length > 0 ? toDaysAgo(Math.max(...allTimestamps)) : null;
  const lastSelfTs = selfMsgs.length > 0 ? Math.max(...selfMsgs.map(m => m?.message?.createAt || 0)) : null;
  const lastClientTs = clientMsgs.length > 0 ? Math.max(...clientMsgs.map(m => m?.message?.createAt || 0)) : null;

  // Last non-system, non-emoji message
  let lastEffectiveMsg = null;
  for (let i = realMessages.length - 1; i >= 0; i--) {
    const m = realMessages[i];
    const content = m?.message?.content?.text?.content || '';
    if (!isEmojiOnly(content)) {
      lastEffectiveMsg = {
        content: content.substring(0, 200),
        isSelf: isSelf(m),
        daysAgo: toDaysAgo(m?.message?.createAt || 0),
        ts: m?.message?.createAt || 0,
      };
      break;
    }
  }

  // Client's last message
  let lastClientMsg = null;
  for (let i = realMessages.length - 1; i >= 0; i--) {
    const m = realMessages[i];
    if (!isSelf(m)) {
      lastClientMsg = {
        content: (m?.message?.content?.text?.content || '').substring(0, 200),
        daysAgo: toDaysAgo(m?.message?.createAt || 0),
      };
      break;
    }
  }

  // Aggregate all signals from all messages
  const allSignals = new Set();
  const recentMsgs = realMessages.slice(-20); // Last 20 messages
  recentMsgs.forEach(m => {
    const content = m?.message?.content?.text?.content || '';
    detectSignals(content).forEach(s => allSignals.add(s));
  });

  // Determine conversation stage
  let stage = 'UNKNOWN';
  const signalArr = Array.from(allSignals);
  if (signalArr.includes('PI') || (signalArr.includes('SPECIFIC_PRICE') && signalArr.includes('SHIPPING'))) {
    stage = 'PI_SENT_WAITING_PAYMENT';
  } else if (signalArr.includes('SPECIFIC_PRICE') && signalArr.includes('PRODUCT')) {
    stage = 'NEGOTIATING';
  } else if (signalArr.includes('PRICE') || signalArr.includes('SPECIFIC_PRICE')) {
    stage = 'QUOTE_SENT';
  } else if (signalArr.includes('PRODUCT') && realMessages.length >= 5) {
    stage = 'PRODUCT_DISCUSSION';
  } else if (realMessages.length >= 3) {
    stage = 'INITIAL_INQUIRY';
  } else {
    stage = 'LOW_ENGAGEMENT';
  }

  // Priority reassessment
  let revisedPriority = null;
  if (signalArr.includes('PI') && lastContact <= 3) revisedPriority = 0;
  if (signalArr.includes('SPECIFIC_PRICE') && signalArr.includes('QTY') && lastContact <= 2) revisedPriority = 0;
  if (clientMsgs.length >= 5 && lastContact <= 2) revisedPriority = Math.min(revisedPriority || 9, 0);

  // Client reply in last 24h
  if (lastClientTs && toDaysAgo(lastClientTs) <= 1) revisedPriority = Math.min(revisedPriority || 9, 0);

  return {
