const fs = require('fs');
const path = require('path');
const { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell, HeadingLevel, AlignmentType, WidthType, BorderStyle, ShadingType } = require('docx');

const SELF_UID = '2500000853693@icbu';

// ==================== DATA ====================

const sysPatterns = [
  '自动接待将不再触发', 'Since you have read the conversation',
  'Marco大模型翻译', '阿里国际Marco大模型翻译',
  '买家有流失风险', 'Buyer has churn risk',
  '一旦离开平台发生纠纷或欺诈', '由于您介入该会话', 'Due to your intervention',
  '反馈', 'AI给您生成了一条回复建议',
  'You have a visitor', 'This buyer has been pre-screened',
];

function isSystemMsg(content) {
  if (!content) return true;
  for (const p of sysPatterns) {
    if (content.includes(p)) return true;
  }
  return false;
}

function isSelf(msg) {
  return msg?.message?.sender?.uid === SELF_UID;
}

function toDaysAgo(ts) {
  return Math.round((Date.now() - ts) / 86400000);
}

const chatDir = path.join(__dirname, '..', 'data', 'chat_history');
const metaPath = path.join(__dirname, '..', 'data', 'tm_conversations_latest.json');
const meta = JSON.parse(fs.readFileSync(metaPath, 'utf8'));

function getConv(cid) {
  const fileName = cid.replace(/#/g, '_').replace(/@/g, '_') + '.json';
  const fp = path.join(chatDir, fileName);
  if (!fs.existsSync(fp)) return null;
  return JSON.parse(fs.readFileSync(fp, 'utf8'));
}

function analyzeConv(cid) {
  const data = getConv(cid);
  if (!data) return { realMsgs: 0, clientMsgs: 0, selfMsgs: 0, lastClientDays: null, lastSelfDays: null, signals: [] };

  const msgs = data.messages || [];
  const real = msgs.filter(m => {
    const ext = m?.message?.extension?.basicMessageInfo;
    if (ext) {
      try { const info = JSON.parse(ext); if (info.systemMessage || info.autoReply) return false; } catch(e) {}
    }
    return !isSystemMsg(m?.message?.content?.text?.content || '');
  });

  const client = real.filter(m => !isSelf(m));
  const self = real.filter(m => isSelf(m));

  const lastClientTs = client.length > 0 ? Math.max(...client.map(m => m?.message?.createAt || 0)) : 0;
  const lastSelfTs = self.length > 0 ? Math.max(...self.map(m => m?.message?.createAt || 0)) : 0;

  // Signals from recent messages
  const recent = real.slice(-30);
  const signals = new Set();
  recent.forEach(m => {
    const c = (m?.message?.content?.text?.content || '').toLowerCase();
    if (c.match(/pi\b|proforma|invoice|发票/)) signals.add('PI');
    if (c.match(/\$\d+|\d+\s*usd|dollar|rmb|价格|سعر|prix|precio/)) signals.add('PRICE');
    if (c.match(/order|下单|pedido|заказ|طلب/)) signals.add('ORDER');
    if (c.match(/address|delivery|ship|freight|地址|物流|envío|livraison|الشحن/)) signals.add('SHIPPING');
    if (c.match(/payment|paid|deposit|付款|定金/)) signals.add('PAYMENT');
    if (c.match(/sample|样品|muestra|عينة/)) signals.add('SAMPLE');
    if (c.match(/style|pattern|color|size|款|色|码/)) signals.add('PRODUCT');
  });

  return {
    total: msgs.length, real: real.length, clientMsgs: client.length, selfMsgs: self.length,
    lastClientDays: lastClientTs ? toDaysAgo(lastClientTs) : null,
    lastSelfDays: lastSelfTs ? toDaysAgo(lastSelfTs) : null,
    signals: Array.from(signals),
  };
}

