  const fileName = cid.replace(/#/g, '_').replace(/@/g, '_') + '.json';
  const fp = path.join(chatDir, fileName);
  if (!fs.existsSync(fp)) return null;
  return JSON.parse(fs.readFileSync(fp, 'utf8'));
}

function analyzeConv(cid) {
  const data = getConv(cid);
  if (!data) return { realMsgs: 0, clientMsgs: 0, selfMsgs: 0, lastClientDays: null, lastSelfDays: null, signals: [] };

  const msgs = data.messages || [];
  const real = msgs.filter(m => {
    const ext = m?.message?.extension?.basicMessageInfo;
    if (ext) {
      try { const info = JSON.parse(ext); if (info.systemMessage || info.autoReply) return false; } catch(e) {}
    }
    return !isSystemMsg(m?.message?.content?.text?.content || '');
  });

  const client = real.filter(m => !isSelf(m));
  const self = real.filter(m => isSelf(m));

  const lastClientTs = client.length > 0 ? Math.max(...client.map(m => m?.message?.createAt || 0)) : 0;
  const lastSelfTs = self.length > 0 ? Math.max(...self.map(m => m?.message?.createAt || 0)) : 0;

  // Signals from recent messages
