  const signals = new Set();
  recent.forEach(m => {
    const c = (m?.message?.content?.text?.content || '').toLowerCase();
    if (c.match(/pi\b|proforma|invoice|发票/)) signals.add('PI');
    if (c.match(/\$\d+|\d+\s*usd|dollar|rmb|价格|سعر|prix|precio/)) signals.add('PRICE');
    if (c.match(/order|下单|pedido|заказ|طلب/)) signals.add('ORDER');
    if (c.match(/address|delivery|ship|freight|地址|物流|envío|livraison|الشحن/)) signals.add('SHIPPING');
