    if (c.match(/pi\b|proforma|invoice|发票/)) signals.add('PI');
    if (c.match(/\$\d+|\d+\s*usd|dollar|rmb|价格|سعر|prix|precio/)) signals.add('PRICE');
    if (c.match(/order|下单|pedido|заказ|طلب/)) signals.add('ORDER');
    if (c.match(/address|delivery|ship|freight|地址|物流|envío|livraison|الشحن/)) signals.add('SHIPPING');
    if (c.match(/payment|paid|deposit|付款|定金/)) signals.add('PAYMENT');
    if (c.match(/sample|样品|muestra|عينة/)) signals.add('SAMPLE');
    if (c.match(/style|pattern|color|size|款|色|码/)) signals.add('PRODUCT');
  });

  return {
    total: msgs.length, real: real.length, clientMsgs: client.length, selfMsgs: self.length,
    lastClientDays: lastClientTs ? toDaysAgo(lastClientTs) : null,
    lastSelfDays: lastSelfTs ? toDaysAgo(lastSelfTs) : null,
    signals: Array.from(signals),
  };
}

